import json, os
p='/app/output/alloc-audit.json'
with open(p) as f: data=json.load(f)
assert isinstance(data, dict)
assert 'cases' in data and isinstance(data['cases'], list)
print('cases:', [c.get('name') for c in data['cases']])
req_case={'name','ok','steps','heap_sig','fl_count','fl_sig','byte_total','ledger'}
req_step={'seq','op','index','size','result_index','heap_sig','fl_count','fl_sig','byte_total'}
missing=[]
for c in data['cases']:
    mc=sorted(req_case - set(c))
    if mc: missing.append((c.get('name'), 'case', mc))
    if not isinstance(c.get('steps'), list):
        missing.append((c.get('name'), 'steps_not_list', []));
        continue
    for i,s in enumerate(c['steps']):
        ms=sorted(req_step - set(s))
        if ms:
            missing.append((c.get('name'), f'step[{i}]', ms))
            break
    led=c.get('ledger')
    if isinstance(led,str):
        if not os.path.exists(led):
            missing.append((c.get('name'), 'ledger_missing', [led]))
    else:
        missing.append((c.get('name'), 'ledger_not_str', []))
print('missing:', missing)
